// 例: 浮動小数点数の計算
var a = 0.1;
var b = 0.2;
console.log(a + b); // 予想される出力: 0.30000000000000004

// 例: nullとundefined
var a;
console.log(a); // 予想される出力: undefined

a = null;
console.log(a); // 予想される出力: null

// 例: 真偽値
var a = '';
console.log(Boolean(a)); // 予想される出力: false

a = 'hello';
console.log(Boolean(a)); // 予想される出力: true

// 例: 型変換
var a = '123';
console.log(typeof a); // 予想される出力: 'string'

a = Number(a);
console.log(typeof a); // 予想される出力: 'number'

// 例: オブジェクト
var person = {
  name: 'John',
  age: 30,
  city: 'Tokyo'
};
console.log(person); // 予想される出力: { name: 'John', age: 30, city: 'Tokyo' }

// 例: 配列
var fruits = ['apple', 'banana', 'cherry'];
console.log(fruits[0]); // 予想される出力: 'apple'

// 例: 関数
function greet(name) {
  return 'Hello, ' + name;
}
console.log(greet('World')); // 予想される出力: 'Hello, World'

// 例: 算術演算子と文字列
var str = 'Hello' + 'World';
console.log(str); // 予想される出力: 'HelloWorld'

str = 'The answer is ' + 42;
console.log(str); // 予想される出力: 'The answer is 42'

// 例: 比較演算子
console.log(5 > 3); // 予想される出力: true
console.log('apple' == 'banana'); // 予想される出力: false

// 例: 真偽値
var isTrue = true;
var isFalse = false;
console.log(isTrue); // 予想される出力: true
console.log(isFalse); // 予想される出力: false

// 例: undefinedとnull
var noValue;
console.log(noValue); // 予想される出力: undefined

var emptyValue = null;
console.log(emptyValue); // 予想される出力: null

// 例: 型変換
var num = 42;
var str = String(num);
console.log(typeof str); // 予想される出力: 'string'

var bool = Boolean('');
console.log(bool); // 予想される出力: false

// 例: NaN
var result = 0 / 0;
console.log(result); // 予想される出力: NaN
console.log(NaN == NaN); // 予想される出力: false

// 例: オブジェクト
var person = {
  name: 'Alice',
  age: 20,
  greet: function() {
    console.log('Hello, ' + this.name);
  }
};
person.greet(); // 予想される出力: 'Hello, Alice'

// 例: 配列
var fruits = ['apple', 'banana', 'cherry'];
console.log(fruits[0]); // 予想される出力: 'apple'
console.log(fruits.length); // 予想される出力: 3

// 例: Date
var now = new Date();
console.log(now); // 予想される出力: 現在の日付と時間

var specificDate = new Date('2022-01-01');
console.log(specificDate); // 予想される出力: 2022-01-01T00:00:00.000Z

// 例: 正規表現
var re1 = /abc/;
console.log(re1.test('abcdef')); // 予想される出力: true

var re2 = new RegExp('abc');
console.log(re2.test('abcdef')); // 予想される出力: true

// 例: Symbol
var symbol1 = Symbol('symbol');
var symbol2 = Symbol('symbol');
console.log(symbol1 === symbol2); // 予想される出力: false

// 例: 関数
function greet(name) {
  return 'Hello, ' + name;
}
console.log(greet('Alice')); // 予想される出力: 'Hello, Alice'

// 例: Promise
var promise = new Promise(function(resolve, reject) {
  // 非同期処理
  var result = true; // 処理の結果
  if (result) resolve('Success!');
  else reject(Error('Failure'));
});
promise.then(function(result) {
  console.log(result); // 予想される出力: 'Success!'
}, function(err) {
  console.log(err);
});
